    // Wait - what about the spec itself being just '/'? That's invalid.
    // What if the regex pattern has a part that ends with /?
    // Looking at compile(): parts are like '/[^/]+', '/foo', '(?:/[^/]+)*' etc.
    // None end with /. So regex never matches trailing slash strings.
    // The mutation is essentially undetectable without a spy!

    const callCount = { value: 0 }
    const original = RegExp.prototype[Symbol.match]
    RegExp.prototype[Symbol.match] = function(str: string) {
      callCount.value++
      return original.call(this, str)
    }
    matcher[Symbol.match]('/foo/')
    RegExp.prototype[Symbol.match] = original
    expect(callCount.value).toBe(0)
  })
